import React, { useState } from "react";
import "./Nav.css";
import logo from "../../assets/logo.png"; // Update path if needed

function Nav({ role, setRole }) {
  const [menuOpen, setMenuOpen] = useState(false);

  const toggleMenu = () => setMenuOpen(!menuOpen);

  const roles = ['Admin', 'Manager', 'Supervisor', 'Labor', 'Client'];

  return (
    <nav className="nav">
      <div className="nav-container">
        <div className="nav-logo">
          <div className="logo-frame">
            <img src={logo} alt="Company Logo" className="company-logo" />
          </div>
        </div>

        <ul className={`nav-links ${menuOpen ? "nav-active" : ""}`}>
          <li><a href="Home">Dashboard</a></li>
          <li><a href="#projects">Projects</a></li>
          <li><a href="#tasks">Tasks</a></li>
          <li><a href="#budget">Budget</a></li>
          <li><a href="#inventory">Inventory</a></li>
          <li><a href="#messages">Messages</a></li>
          <li><a href="#reports">Reports</a></li>
          <li><a href="#settings">Settings</a></li>
        </ul>

        <div className="nav-user-controls">
          {role ? (
            <>
              <span className="user-role">Role: {role}</span>
              <button
                className="logout-button"
                onClick={() => setRole(null)}
                aria-label="Logout"
              >
                Logout
              </button>
            </>
          ) : (
            <select
              value=""
              onChange={(e) => setRole(e.target.value)}
              aria-label="Select user role to login"
            >
              <option value="" disabled>Select Role</option>
              {roles.map(r => (
                <option key={r} value={r}>{r}</option>
              ))}
            </select>
          )}
        </div>

        <div 
          className={`burger ${menuOpen ? "toggle" : ""}`} 
          onClick={toggleMenu}
          aria-label="Toggle navigation menu"
          role="button"
          tabIndex={0}
          onKeyPress={e => { if(e.key === 'Enter') toggleMenu(); }}
        >
          <div className="line1"></div>
          <div className="line2"></div>
          <div className="line3"></div>
        </div>
      </div>
    </nav>
  );
}

export default Nav;
